// ===============================
// src/components/FileUpload.js
// ===============================
import React from "react";

function FileUpload({ setFile }) {
  return (
    <input
      type="file"
      accept="image/*"
      onChange={(e) => setFile(e.target.files[0])}
    />
  );
}

export default FileUpload;
